  ('diplomatic-d3cf880d-moex-00224', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-113-c655adf3', 'sub-diplomatic-d3cf880d-05', NULL, 'single_choice', '臺灣面臨中共對臺複合性施壓，為了展現守護國家的決心，賴清德總統提出「和平四大支柱行動方案」， 下列何者不是其中的方案？', '["談判兩岸軍事互信機制與和平協議", "強化國防和不對稱戰力，建立臺灣的嚇阻力量", "深化與國際社會和民主國家的合作關係", "強化經濟安全和供應鏈的韌性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:46+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00225', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-113-c655adf3', 'sub-diplomatic-d3cf880d-05', NULL, 'single_choice', '2022年10月中國共產黨召開第二十次全國代表大會（簡稱中共二十大），下列敘述何者錯誤？', '["二十大習近平的《政治報告》中，自2002年中共十六大之後，再次出現「不承諾放棄使用武力」來 處理臺灣問題。十七至十九屆《政治報告》均未提及「不承諾放棄使用武力」此語", "7位中共政治局常委全是「習近平派」，習近平權力一把抓", "習近平在二十大上破例連任第三屆中共總書記，打破鄧小平時代以來只做兩屆10年的慣例", "習近平在二十大上，延續慣例做了5年後二十一大的接班人安排，承諾不會爭取第四個任期"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:46+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00226', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-113-c655adf3', 'sub-diplomatic-d3cf880d-05', NULL, 'single_choice', '有關臺灣地區與大陸地區人民關係條例相關規定，下列敘述何者錯誤？', '["該條例關於大陸地區人民之規定，於大陸地區人民旅居國外者，不適用之", "大陸委員會統籌處理有關大陸事務，為本條例之主管機關", "該條例第1條第一句話是：「國家統一前」", "行政院得設立或指定機構，處理兩岸人民往來有關之事務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:46+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00227', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-113-c655adf3', 'sub-diplomatic-d3cf880d-05', NULL, 'single_choice', '近年來與中共有明顯海上衝突的國家，是下列那兩個？', '["日本與菲律賓", "日本與新加坡", "菲律賓與馬來西亞", "馬來西亞與泰國"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:46+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00228', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-113-c655adf3', 'sub-diplomatic-d3cf880d-05', NULL, 'single_choice', '有關中共僑務工作的敘述何者錯誤？', '["最高主管單位是國務院僑務辦公室，簡稱「國僑辦」", "中共各省、市、自治區都設有僑務工作相關辦公室", "中共僑務工作為「國僑辦」所專屬，外交部並不負責", "「國僑辦」在2018年併入中共中央統一戰線工作部"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:46+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00229', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-113-c655adf3', 'sub-diplomatic-d3cf880d-05', NULL, 'single_choice', '有關中共「一帶一路」的敘述，下列何者錯誤？', '["是中共總書記胡錦濤在2013年提出，協助外國進行基礎建設", "全名是「絲綢之路經濟帶」與「21世紀海上絲綢之路」", "搭配成立「亞洲基礎設施投資銀行」以提供外國貸款", "義大利在2023年宣布退出"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:46+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00230', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-113-c655adf3', 'sub-diplomatic-d3cf880d-05', NULL, 'single_choice', '對於「海協會」的敘述，下列何者錯誤？', '["全名是海峽兩岸關係協會", "是中共處理兩岸事務的單位，對口單位是我國的財團法人海峽交流基金會", "為一民間機構，不受中共黨政機關所控制", "現任會長是張志軍，為前任國台辦主任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:46+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
