  ('diplomatic-d3cf880d-moex-00232', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-113-c655adf3', 'sub-diplomatic-d3cf880d-05', NULL, 'single_choice', '半總統制國家依總統或總理所掌握之行政權大小又分為總理－總統制及總統－總理制；請問下列何者 為半總統制國家？', '["印度", "俄羅斯", "瑞典", "新加坡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:46+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00233', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-113-c655adf3', 'sub-diplomatic-d3cf880d-05', NULL, 'single_choice', '關於冷戰時期同屬社會主義陣營的中共與前蘇聯之改革開放經驗，下列敘述何者正確？', '["中共的改革有其時序，先政後經，但仍維持共產黨一黨專政的地位", "前蘇聯的改革是以一套長期的政策來建立市場經濟，以達宏觀經濟穩定", "兩國的改革開放皆面臨因經濟與生產工具由國家轉移到私人手中所致的貪污", "前蘇聯的改革模式為「漸進模式」，中共為「震盪療法」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:46+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL)
